import json
# Read the JSONL file (one JSON per line)
results = []
for fname in ['paper_search_results/cipher_text_language_model_robustness_token_permutation_20260322_124428.jsonl']:
    with open(fname) as f:
        for line in f:
            line = line.strip()
            if line:
                try:
                    d = json.loads(line)
                    if 'papers' in d:
                        for p in d['papers']:
                            if p.get('relevance',0) >= 2:
                                results.append(p)
                    elif 'title' in d:
                        if d.get('relevance',0) >= 2:
                            results.append(d)
                except:
                    pass
for p in results[:30]:
    print(f\"{p.get('relevance',0)} | {p.get('year','?')} | {p.get('citations','?')} | {p['title'][:90]}\")
if not results:
    print('No high-relevance results')
